{
  "grammar": [
    {
      "pattern": "Subject + 穿 + size/color + 的 + clothing item",
      "structure": ["Subject", "穿", "size/color", "的", "clothing item"],
      "explanation_en": "Use this pattern to describe what size or color of clothing someone is wearing or wants to try on.",
      "title": "Describing Clothing Size/Color",
      "meaning": "Someone wears a certain size/color of clothing.",
      "when_to_use": ["When asking for a specific size or color", "When describing what you or someone else is wearing"],
      "when_not_to_use": ["When talking about the material or brand", "When the clothing item is not specified"],
      "pragmatic_notes": "In Taiwan, it's common to say '我穿小號的' (I wear small size) or '我要紅色的上衣' (I want a red top).",
      "word_order_notes": "The size or color comes before '的' and the clothing item.",
      "english_contrast": "English says 'I wear a small shirt' but Chinese requires '的' between size/color and item.",
      "korean_contrast": "Korean uses '을/를' after the item, but Chinese uses '的' before the item.",
      "negative_examples": [
        {
          "text": "我穿小號上衣。",
          "error": "Missing '的' between size and clothing item."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我穿小號上衣。",
          "error": "Should be '我穿小號的上衣。'"
        }
      ],
      "transformation_drills": ["Change '我穿小號的上衣' to '他穿大號的褲子'."],
      "production_drills": ["Say you want to try on a blue jacket."],
      "common_error_patterns": ["Omitting '的' between size/color and clothing item"],
      "repair_feedback": {
        "word_order": "Put size/color before '的' and clothing item after.",
        "politeness": "Use '請' or '不好意思' for polite requests.",
        "vocabulary": "Use correct clothing words like '上衣', '褲子', '外套'."
      }
    },
    {
      "pattern": "Subject + 太 + adjective + 了",
      "structure": ["Subject", "太", "adjective", "了"],
      "explanation_en": "Use this pattern to express that something is excessively adjective (e.g., too big, too expensive).",
      "title": "Expressing Excessiveness with 太...了",
      "meaning": "Something is too (adjective).",
      "when_to_use": ["When complaining about size or price", "When giving feedback on fit"],
      "when_not_to_use": ["When describing something that is just right", "When the adjective is positive without excess"],
      "pragmatic_notes": "In Taiwan, '太貴了' (too expensive) is common in bargaining. '太大了' (too big) is used when trying on clothes.",
      "word_order_notes": "Place '太' before the adjective and '了' at the end of the sentence.",
      "english_contrast": "English says 'too big' but Chinese uses '太大了' with '了' at the end.",
      "korean_contrast": "Korean uses '너무' before adjective, but Chinese uses '太...了' structure.",
      "negative_examples": [
        {
          "text": "這件上衣太大。",
          "error": "Missing '了' at the end to express excessiveness."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這件上衣太大。",
          "error": "Should be '這件上衣太大了。'"
        }
      ],
      "transformation_drills": ["Change '這件褲子太小' to '這件褲子太小了。'"],
      "production_drills": ["Say the shoes are too expensive."],
      "common_error_patterns": ["Omitting '了' in the 太...了 structure"],
      "repair_feedback": {
        "word_order": "Place '太' before adjective and '了' at the end.",
        "politeness": "Use '不好意思' before complaining.",
        "vocabulary": "Use adjectives like '大', '小', '貴', '便宜'."
      }
    },
    {
      "pattern": "Subject + 有沒有 + size/color + 的 + clothing item",
      "structure": ["Subject", "有沒有", "size/color", "的", "clothing item"],
      "explanation_en": "Use this pattern to ask if a certain size or color of a clothing item is available.",
      "title": "Asking for Availability of Size/Color",
      "meaning": "Do you have (size/color) of (clothing item)?",
      "when_to_use": ["When looking for a specific size or color in a store", "When checking stock"],
      "when_not_to_use": ["When asking about price or material", "When the item is not clothing"],
      "pragmatic_notes": "In Taiwan, it's polite to say '請問，你們有沒有黑色的外套？' (Excuse me, do you have a black jacket?).",
      "word_order_notes": "Place '有沒有' after the subject, then size/color, then '的', then clothing item.",
      "english_contrast": "English says 'Do you have a black jacket?' but Chinese uses '有沒有' and '的'.",
      "korean_contrast": "Korean uses '있어요?' at the end, but Chinese uses '有沒有' in the middle.",
      "negative_examples": [
        {
          "text": "你有沒有黑色外套？",
          "error": "Missing '的' between color and clothing item."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你有沒有黑色外套？",
          "error": "Should be '你有沒有黑色的外套？'"
        }
      ],
      "transformation_drills": ["Change '你有沒有小號的上衣？' to '你有沒有大號的褲子？'"],
      "production_drills": ["Ask if they have a blue skirt."],
      "common_error_patterns": ["Omitting '的' between size/color and clothing item"],
      "repair_feedback": {
        "word_order": "Put '有沒有' after subject, then size/color, then '的', then item.",
        "politeness": "Start with '請問' for politeness.",
        "vocabulary": "Use correct color and clothing words."
      }
    }
  ]
}
